class CricketAgentRuntime:
    """Human-in-the-loop agent runtime with cricket-themed state management."""

    def __init__(self, agent_name: str, context_window: int = 5000):
        self.agent_name = agent_name
        self.state_vector = {
            'current_runs': 0,
            'wickets_lost': 0,
            'overs_completed': 0,
            'bowler_performance': {},
            'field_placement': [],
            'confidence_scores': {}
        }
        self.execution_history = []
        self.context_window = context_window
        self.memory_tokens_used = 0

    def execute_tool_call(self, tool_name: str, params: dict) -> dict:
        """Execute tool and update agent state atomically."""
        print(f"[{self.agent_name}] Executing tool: {tool_name}")

        tool_result = self._invoke_tool(tool_name, params)
        self.state_vector.update(tool_result.get('state_delta', {}))
        self.execution_history.append({
            'tool': tool_name,
            'params': params,
            'result': tool_result,
            'timestamp': self._get_timestamp()
        })
        self.memory_tokens_used += tool_result.get('tokens_consumed', 0)

        return tool_result

    def evaluate_confidence(self, decision: str) -> float:
        """Compute confidence score; if < threshold, request human input."""
        recent_outcomes = self.execution_history[-10:]
        success_rate = sum(1 for h in recent_outcomes if h['result'].get('success')) / max(len(recent_outcomes), 1)

        confidence = success_rate * 0.6 + (1.0 - abs(self.state_vector['overs_completed'] / 20 - 0.5)) * 0.4

        print(f"[Confidence] Decision '{decision}': {confidence:.2f}")
        return confidence

    def request_human_approval(self, decision: str, context: dict) -> bool:
        """Pause execution and escalate to human operator."""
        print(f"\n[ESCALATION] Awaiting human input for: {decision}")
        print(f"Context: {context}")
        print(f"Agent History (last 3 actions): {self.execution_history[-3:]}")

        approval = input("Approve (y/n): ").strip().lower() == 'y'
        self.state_vector['last_human_decision'] = (decision, approval)
        return approval

    def plan_and_execute(self, objective: str, approval_threshold: float = 0.7) -> dict:
        """Main execution loop with human-in-the-loop checkpoint."""
        plan = self._generate_plan(objective)
        print(f"[Plan] Generated {len(plan)} actions for: {objective}")

        for action_idx, action in enumerate(plan):
            confidence = self.evaluate_confidence(action['description'])

            if confidence < approval_threshold:
                approved = self.request_human_approval(
                    action['description'],
                    {'state': self.state_vector, 'action': action}
                )
                if not approved:
                    print(f"[Plan] Action rejected by human. Regenerating plan.")
                    return {'status': 'halted', 'last_action': action_idx}

            result = self.execute_tool_call(action['tool'], action['params'])

            if self.memory_tokens_used > self.context_window:
                self._compact_memory()

        return {'status': 'completed', 'final_state': self.state_vector}

    def _generate_plan(self, objective: str) -> list:
        """Generate action plan (stubbed for brevity)."""
        return [
            {'description': 'Assess pitch conditions', 'tool': 'analyze_pitch', 'params': {'surface_type': 'hard'}},
            {'description': 'Place fielders for spinner', 'tool': 'set_field', 'params': {'bowler_type': 'spinner'}},
            {'description': 'Review batsman form', 'tool': 'check_batsman_stats', 'params': {'vs_spinners': True}}
        ]

    def _invoke_tool(self, tool_name: str, params: dict) -> dict:
        """Invoke external tool (stubbed)."""
        return {'success': True, 'state_delta': {'overs_completed': self.state_vector['overs_completed'] + 1}, 'tokens_consumed': 120}

    def _compact_memory(self):
        """Prune old history, retain recent interactions and summaries."""
        self.execution_history = self.execution_history[-20:]
        self.memory_tokens_used = 0
        print("[Memory] Compacted execution history.")

    def _get_timestamp(self) -> str:
        from datetime import datetime
        return datetime.now().isoformat()

# Usage
agent = CricketAgentRuntime(agent_name="Rohit_Captain_Agent", context_window=10000)
result = agent.plan_and_execute("Maximize runs in powerplay overs", approval_threshold=0.75)

# ANTI-PATTERN: No checkpoints, agent makes everything autonomously
class BattingAgentAntiPattern:
    def decide_shot(self, ball_delivery):
        confidence = self.evaluate_confidence(ball_delivery)
        if confidence > 0.6:  # Arbitrary threshold, no human involvement
            action = self.execute_stroke(ball_delivery)
            self.update_score(action)
            return action
        # What happens when confidence fails? No recovery mechanism

# BEST PRACTICE: Checkpoint pattern with human validation gates
class BattingAgentBestPractice:
    def decide_shot(self, ball_delivery, human_validator):
        # Agent analyzes, human validates for risky decisions
        confidence = self.evaluate_confidence(ball_delivery)

        if confidence > 0.85:  # High confidence path
            action = self.execute_stroke(ball_delivery)
            self.log_decision(action, confidence, "autonomous")
            return action

        elif confidence > 0.50:  # Medium confidence requires human checkpoint
            recommendation = self.generate_recommendation(ball_delivery)
            human_decision = human_validator.review_and_approve(
                recommendation=recommendation,
                confidence=confidence,
                context={
                    "match_situation": self.match_state,
                    "bowler_analysis": self.analyze_bowler(),
                    "risk_level": self.calculate_risk_level()
                }
            )
            if human_decision.approved:
                action = self.execute_stroke(ball_delivery)
                self.log_decision(action, confidence, "human_validated")
                return action
            else:
                return self.safe_defense_action(ball_delivery)

        else:  # Low confidence: escalate to human
            return human_validator.make_decision(
                situation=ball_delivery,
                agent_analysis=self.full_analysis(ball_delivery)
            )

