from enum import Enum
from dataclasses import dataclass

class DecisionConfidence(Enum):
    HIGH = 0.9
    MEDIUM = 0.6
    LOW = 0.3

@dataclass
class RunDecision:
    runs: int
    confidence: float
    requires_human_review: bool
    reason: str

class CricketScoringAgent:
    def __init__(self, confidence_threshold=0.7):
        self.confidence_threshold = confidence_threshold
        self.escalation_queue = []

    def evaluate_run(self, ball_event: dict) -> RunDecision:
        """Agent makes autonomous run scoring decisions or escalates."""
        runs = ball_event.get('runs', 0)
        ambiguity_score = self._calculate_ambiguity(ball_event)
        confidence = 1.0 - ambiguity_score

        # Autonomous decision (high confidence)
        if confidence >= self.confidence_threshold:
            return RunDecision(
                runs=runs,
                confidence=confidence,
                requires_human_review=False,
                reason="Clear run scoring decision"
            )

        # Escalate to human (low confidence)
        self.escalation_queue.append({
            'event': ball_event,
            'confidence': confidence,
            'timestamp': ball_event['timestamp']
        })

        return RunDecision(
            runs=runs,
            confidence=confidence,
            requires_human_review=True,
            reason=f"Ambiguous run: {ball_event.get('description')}"
        )

    def _calculate_ambiguity(self, ball_event: dict) -> float:
        """Heuristic: higher score = less certain."""
        factors = [
            0.3 if ball_event.get('fielder_distance', 10) < 2 else 0.0,  # Close catch
            0.2 if 'boundary_question' in ball_event.get('tags', []) else 0.0,
            0.1 if ball_event.get('player_injured') else 0.0
        ]
        return min(sum(factors), 1.0)

    def process_human_feedback(self, decision_id: str, human_verdict: int) -> dict:
        """Incorporate human feedback to refine future decisions."""
        return {
            'decision_id': decision_id,
            'feedback_recorded': True,
            'model_adjustment': 'confidence_threshold_updated'
        }

# Usage
agent = CricketScoringAgent(confidence_threshold=0.75)
event = {
    'runs': 4,
    'timestamp': '2024-01-15T14:23:45',
    'description': 'Edge to boundary, possibly grounded',
    'fielder_distance': 1.5,
    'tags': ['boundary_question']
}

decision = agent.evaluate_run(event)
print(f"Decision: {decision.runs} runs | Confidence: {decision.confidence:.2%}")
print(f"Human review needed: {decision.requires_human_review} ({decision.reason})")
